/// A 10-character ASCII battery bar, e.g. [████████░░]
fn battery_bar(current: f64, max: f64) -> String {
    let filled = ((current / max) * 10.0).round() as usize;
    let filled  = filled.min(10);
    let empty   = 10 - filled;
    let bar: String = "█".repeat(filled) + &"░".repeat(empty);
    let color = if current / max < 0.25 {
        "\x1b[31m" // red when low
    } else if current / max < 0.5 {
        "\x1b[33m" // yellow when medium
    } else {
        "\x1b[32m" // green when good
    };
    format!("{}{}\x1b[0m", color, bar)
}

fn separator(label: &str) -> String {
    let prefix = "─".repeat(4);
    let suffix = "─".repeat(54usize.saturating_sub(label.len().min(50)));
    format!("  {} {} {}", prefix, label, suffix)
}
